const fs = require('fs');
const path = require('path');
const http = require('http');
const url = require('url');

function createApp() {
  const middlewares = [];
  const routes = [];

  const app = {
    use(pathOrFn, maybeFn) {
      if (typeof pathOrFn === 'string' && typeof maybeFn === 'function') {
        middlewares.push({ prefix: pathOrFn, fn: maybeFn });
      } else {
        middlewares.push({ prefix: '/', fn: pathOrFn });
      }
    },
    get(routePath, handler) {
      routes.push({ method: 'GET', path: routePath, handler });
    },
    post(routePath, handler) {
      routes.push({ method: 'POST', path: routePath, handler });
    },
    listen(port, cb) {
      const server = http.createServer((req, res) => {
        enhanceRes(res);
        req.path = url.parse(req.url).pathname;
        req.query = Object.fromEntries(new URL(req.url, 'http://localhost').searchParams.entries());

        const stack = [
          ...middlewares.filter((m) => req.path.startsWith(m.prefix)).map((m) => m.fn),
          routeDispatcher(routes),
        ];

        let i = 0;
        const next = () => {
          const fn = stack[i++];
          if (!fn) {
            res.statusCode = 404;
            res.end('Not Found');
            return;
          }
          fn(req, res, next);
        };
        next();
      });
      return server.listen(port, cb);
    },
  };

  return app;
}

function routeDispatcher(routes) {
  return (req, res, next) => {
    const match = routes.find((route) => route.method === req.method && route.path === req.path);
    if (!match) return next();
    return match.handler(req, res, next);
  };
}

function enhanceRes(res) {
  res.status = function status(code) {
    res.statusCode = code;
    return res;
  };

  res.json = function json(payload) {
    res.setHeader('Content-Type', 'application/json');
    res.end(JSON.stringify(payload));
  };

  res.send = function send(payload) {
    if (typeof payload === 'string') {
      res.end(payload);
      return;
    }
    res.json(payload);
  };

  res.sendFile = function sendFile(filePath) {
    fs.readFile(filePath, (err, buffer) => {
      if (err) {
        res.statusCode = 404;
        res.end('Not Found');
        return;
      }
      const ext = path.extname(filePath);
      const type =
        {
          '.html': 'text/html',
          '.css': 'text/css',
          '.js': 'application/javascript',
          '.json': 'application/json',
          '.jpg': 'image/jpg',
          '.woff2': 'font/woff2',
        }[ext] || 'application/octet-stream';
      res.setHeader('Content-Type', type);
      res.end(buffer);
    });
  };

  res.redirect = function redirect(location) {
    res.statusCode = 302;
    res.setHeader('Location', location);
    res.end();
  };
}

function staticMiddleware(root) {
  return (req, res, next) => {
    const filePath = path.join(root, decodeURIComponent(req.path));
    if (!filePath.startsWith(root)) {
      next();
      return;
    }
    fs.stat(filePath, (err, stat) => {
      if (err || !stat.isFile()) {
        next();
        return;
      }
      res.sendFile(filePath);
    });
  };
}

function bodyParser(format) {
  return (req, _res, next) => {
    if (req.method !== 'POST' && req.method !== 'PUT' && req.method !== 'PATCH') {
      next();
      return;
    }

    const type = req.headers['content-type'] || '';
    const wantsJson = format === 'json' && type.includes('application/json');
    const wantsForm = format === 'urlencoded' && type.includes('application/x-www-form-urlencoded');

    if (!wantsJson && !wantsForm) {
      next();
      return;
    }

    const chunks = [];
    req.on('data', (chunk) => chunks.push(chunk));
    req.on('end', () => {
      const raw = Buffer.concat(chunks).toString('utf8');
      if (wantsJson) {
        try {
          req.body = raw ? JSON.parse(raw) : {};
        } catch (_err) {
          req.body = {};
        }
      } else if (wantsForm) {
        req.body = Object.fromEntries(new URLSearchParams(raw).entries());
      }
      next();
    });
  };
}

function express() {
  return createApp();
}

express.static = staticMiddleware;
express.urlencoded = () => bodyParser('urlencoded');
express.json = () => bodyParser('json');

module.exports = express;